server/tests/test_pipeline.py :: test_max_bytes_from_mb_default
def test_max_bytes_from_mb_default() -> None:
    assert max_bytes_from_mb(None) == 1024 * 1024

server/tests/test_pipeline.py :: test_max_bytes_from_mb_custom
def test_max_bytes_from_mb_custom() -> None:
    assert max_bytes_from_mb(2) == 2 * 1024 * 1024

server/tests/test_pipeline.py :: test_max_bytes_rejects_out_of_range
def test_max_bytes_rejects_out_of_range() -> None:
    try:
        max_bytes_from_mb(30)
    except ValueError:
        return
    raise AssertionError("Expected ValueError")
